const p = $input.first().json;
if (!p.cliente_id && !p.codigo) {
  throw new Error('Parâmetro obrigatório ausente: informe cliente_id ou codigo da OS para buscar.');
}
// Normalizar cliente_id para número inteiro
if (p.cliente_id && !/^[0-9]+$/.test(String(p.cliente_id))) {
  throw new Error(`cliente_id inválido: "${p.cliente_id}". Deve ser um número inteiro.`);
}
return [{ json: {
  cliente_id: p.cliente_id ? String(p.cliente_id) : null,
  codigo: p.codigo ? String(p.codigo) : null
} }];

const data = $input.first().json;
const oss = data.data || [];
if (oss.length === 0) {
  return [{ json: { resultado: 'Nenhuma OS encontrada para este cliente. Deseja abrir uma nova OS?', ordens: [] } }];
}
const lista = oss.slice(0, 5).map(os => ({
  id: os.id,
  os_id: os.id,
  codigo: os.codigo,
  situacao: os.nome_situacao,
  situacao_id: os.situacao_id,
  data_entrada: os.data_entrada || os.data,
  valor_total: os.valor_total,
  observacoes: os.observacoes ? os.observacoes.substring(0, 100) : ''
}));
const textoLista = lista.map((os, i) => `${i+1}. OS #${os.codigo} | ID interno: ${os.id} | Status: ${os.situacao} | Data: ${os.data_entrada} | Valor: R$${os.valor_total}${os.observacoes ? ' | '+os.observacoes+'...' : ''}`).join('\n');
const option_map = {};
lista.forEach((os, i) => { option_map[String(i+1)] = { os_id: os.id, os_codigo: os.codigo, situacao: os.situacao }; });
return [{ json: { resultado: `OS encontradas:\n${textoLista}\n\nQual deseja trabalhar? Informe o número.`, ordens: lista, option_map } }];
